#!/usr/bin/env python3
"""
Project Generator: Energy Commodities Systematic Trading Platform
Recreates the entire project source tree from scratch.

Usage:
    python generate_project_commodities.py
    python generate_project_commodities.py --target-dir /path/to/new/project
"""
import argparse
import base64
import json
from pathlib import Path

_FILES_B64 = ""

FILES = json.loads(base64.b64decode(_FILES_B64).decode("utf-8"))


def generate(target_dir: str = "."):
    root = Path(target_dir)
    for rel_path, content in FILES.items():
        path = root / rel_path
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8")
        print(f"  wrote {rel_path}")
    print(f"\nGenerated {len(FILES)} files in {root.resolve()}")


if __name__ == "__main__":
    parser = argparse.ArgumentParser(description="Generate project files")
    parser.add_argument("--target-dir", default=".", help="Target directory")
    args = parser.parse_args()
    generate(args.target_dir)
